def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 45.0 + np.log1p(cap ** 1.5) * 30 + np.sqrt(cap) * 12
        fluctuation = 0.0
        noise_scale = 7.5
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.25)
            if cap > 15:
                base_priority += 150 * np.cbrt(cap) + 40 * np.cos(cap * 1.2) - 20 * np.sin(cap / 3)
            else:
                base_priority -= 50 * usage + 5 * np.log1p(usage)
            for i in range(1, 7):
                fluctuation += ((-1) ** (i)) * np.sin(usage * np.pi * i * 0.6) * noise_scale / i
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2500 * delta ** 2.1 + 300 * (1 - np.sqrt(delta))
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.1)) * 30 / j - np.sin(j * cap / 7) * 5
            if int(cap * 4) % 5 == 0:
                base_priority += 50 * np.tan(cap / 18)
        elif 3 < usage <= 4:
            base_priority += 1800 * (usage - 3) ** 1.7 + 220 * np.exp(-usage)
            for k in range(1, 13):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 15 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 22 / (k + 3)
                    if k == 11 and usage > 3.5:
                        fluctuation += 25
            if cap % 3.1 < 0.7:
                base_priority += 40 * np.sin(cap * 2.5)
        elif 2 < usage <= 3:
            base_priority += 1400 * (usage - 2) ** 2.3
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.7:
                    fluctuation += pwr * 20 / m
                    if m % 6 == 2:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 3)
                    if m == 16 and usage > 2.4:
                        fluctuation += 18
            if cap % 2.7 < 0.4:
                base_priority += 30 * np.cos(cap * 3.2)
        elif 1 < usage <= 2:
            base_priority += 1000 * (usage - 1) ** 3.5
            for n in range(1, 22):
                pwr = usage ** n
                if pwr < 0.5:
                    fluctuation += pwr * 30 / n
                    if n % 5 == 3:
                        fluctuation -= 5 * n
                else:
                    fluctuation += (1 - pwr) * 18 / (n + 2)
                    if n == 18 and usage > 1.8:
                        fluctuation += 22
            if cap % 1.7 < 0.5:
                base_priority += 35 * np.sin(cap * 2.8)
        elif 0.4 < usage <= 1:
            base_priority += 160 * (1 - usage)**1.3 + 20 * np.log1p(usage)
            for o in range(1, 14):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 18 / o
                if usage < 0.05 * o:
                    fluctuation -= 7 * o
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.2:
                base_priority += np.log1p(cap * 22) * 38
            else:
                base_priority += (cap % 7) * 28
        else:
            base_priority += 320 * (1 - usage) ** 2.7
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 8) - 0.2) * 17 / p
                if usage < 0.01 * p:
                    fluctuation -= 14 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.0:
                base_priority += np.log1p(cap * 30) * 48
            else:
                base_priority += (cap % 8) * 35
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 90
            if usage > 0.8:
                priority += 110
            elif usage < 0.1:
                priority -= 60
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.1:
            priority += 50
            if usage > 0.9:
                priority += 75
            elif usage < 0.25:
                priority -= 40
            for s in range(1, 8):
                if int(cap * 1400) % (s + 5) == 0:
                    priority += s * 8
                else:
                    priority -= s * 4
        else:
            if usage < 0.15:
                priority -= 60
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.94:
                priority += 110
                for u in range(1, 6):
                    priority += u * 12
            else:
                priority += 45
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 18
        if int(cap * 1100) % 29 == 0:
            proximity -= 13
        if int(cap * 220) % 11 == 0:
            proximity += 16
        for w in range(1, 11):
            diff = abs(usage - w / 11)
            if diff < 0.015:
                proximity += 25 / w
            elif diff < 0.04:
                proximity += 13 / w
            else:
                proximity -= 6 / w
        for x in range(1, 9):
            mod_chk = int(cap * 1800) % (x + 11)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 7):
            mod_chk = int(usage * 1800) % (y + 8)
            if mod_chk == 0:
                proximity += 12 * y
            elif mod_chk == 4:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.003:
            for z in range(1, 10):
                priority -= z * 12
        elif usage > 0.97:
            for aa in range(1, 8):
                priority += aa * 14
        if cap > 3.0:
            if cap % 1.2 < 0.08:
                priority += 50
            if (int(cap * 3500) % 29 == 0) and (usage > 0.75):
                priority += 75
            for bb in range(1, 7):
                if (int(cap * 800) % (bb + 11) == 3) and (usage < 0.9):
                    priority -= 30
            if cap % 0.7 < 0.1:
                priority += 25 * np.sin(cap * 4)
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        perturb = 0.0
        for cc in range(1, 20):
            perturb += np.sin(cc * usage * np.pi / (cc + 5)) * 10 / cc
            if cc % 4 == 0:
                perturb -= np.cos(cap * cc / 10) * 6 / (cc + 1)
            else:
                perturb += np.tanh((usage * cap) / (cc + 2)) * 4 / (cc + 1)
        priority += perturb
        priorities[idx] = priority
    return priorities
